logic sig_c_1;
logic sig_c_2;
function logic get_c1();
  return sig_c_2;
endfunction
always @* begin
  if (get_c1())
    sig_c_2 = 1'b0;
  else
    sig_c_2 = 1'b1;
  sig_c_1 = get_c1();
end

logic a;
logic b;
function logic get_a();
  return b;
endfunction
always @* begin
  if (get_a())
    if (1'b1)
      b = 1'b0;
    else
      b = 1'b1;
end
